import scala.collection.mutable.{Queue, HashMap, ArrayBuffer}

def isPrime(num: Long): Boolean = {
    if (num <= 1) false
    else if (num == 2) true
    else if (num % 2 == 0) false
    else {
        var i = 3L
        while (i * i <= num) {
            if (num % i == 0) return false
            i += 2
        }
        true
    }
}

def solve(nums: Array[Long]): Long = {
    val n = nums.length
    if (n == 1) return 0L

    val primeToIndices = HashMap[Long, ArrayBuffer[Int]]()
    for (i <- 0 until n) {
        val num = nums(i)
        if (isPrime(num)) {
            primeToIndices.getOrElseUpdate(num, ArrayBuffer()) += i
        }
    }

    val divisibleIndices = HashMap[Long, ArrayBuffer[Int]]()
    for (i <- 0 until n) {
        val num = nums(i)
        for ((p, _) <- primeToIndices) {
